{
  "name": "KKTC CPI Analyzer",
  "description": "Professional financial visualization tool for analyzing consumer price index data of Northern Cyprus relative to exchange rates and commodities."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface MarketDataPoint {
  date: string; // ISO format YYYY-MM-DD
  timestamp: number;
  [key: string]: number | string;
}

export interface ExchangeRates {
  [date: string]: {
    USD: number;
    EUR: number;
    GBP: number;
    BRENT_TL: number;
    BRENT_USD: number;
  };
}

export enum Currency {
  TRY = 'TRY',
  USD = 'USD',
  EUR = 'EUR',
  BRENT = 'BRENT'
}

export enum ScaleType {
  LINEAR = 'Linear',
  LOG = 'Logarithmic',
  PERCENTAGE = '%'
}

export interface SeriesConfig {
  id: string;
  name: string;
  color: string;
}

import React from 'react';

const Header: React.FC = () => {
  return (
    <header className="bg-slate-900 border-b border-slate-700 px-6 py-4 flex items-center justify-between">
      <div className="flex items-center gap-3">
        <div className="w-8 h-8 bg-blue-600 rounded-md flex items-center justify-center">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 12l3-3 3 3 4-4M8 21l4-4 4 4M3 4h18M4 4h16v12a1 1 0 01-1 1H5a1 1 0 01-1-1V4z" />
            </svg>
        </div>
        <div>
            <h1 className="text-xl font-bold text-slate-100 tracking-tight">KKTC CPI Analyzer</h1>
            <p className="text-xs text-slate-400">Historical Price & Currency Analysis (2015-2025)</p>
        </div>
      </div>
    </header>
  );
};

export default Header;

import React, { useState, useRef, useEffect } from 'react';
import { Currency, ScaleType } from '../types';
import { availableItems } from '../services/dataService';

interface ControlsProps {
  selectedItems: string[];
  onItemsChange: (items: string[]) => void;
  currency: Currency;
  onCurrencyChange: (c: Currency) => void;
  scale: ScaleType;
  onScaleChange: (s: ScaleType) => void;
  dateRange: [string, string];
  onDateRangeChange: (range: [string, string]) => void;
  minDate: string;
  maxDate: string;
}

const Controls: React.FC<ControlsProps> = ({
  selectedItems,
  onItemsChange,
  currency,
  onCurrencyChange,
  scale,
  onScaleChange,
  dateRange,
  onDateRangeChange,
  minDate,
  maxDate
}) => {
  const [isDropdownOpen, setIsDropdownOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const dropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsDropdownOpen(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const toggleItem = (item: string) => {
    if (selectedItems.includes(item)) {
      onItemsChange(selectedItems.filter(i => i !== item));
    } else {
      if (selectedItems.length < 5) {
        onItemsChange([...selectedItems, item]);
      }
    }
  };

  const filteredItems = availableItems.filter(item => 
    item.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="bg-slate-800 border-b border-slate-700 p-4 flex flex-col lg:flex-row gap-4 lg:items-center justify-between sticky top-0 z-50 shadow-lg">

      {/* Item Selector */}
      <div className="relative w-full lg:w-96" ref={dropdownRef}>
        <div 
            className="bg-slate-900 border border-slate-600 rounded px-3 py-2 cursor-pointer text-sm text-slate-200 flex justify-between items-center hover:border-blue-500 transition-colors"
            onClick={() => setIsDropdownOpen(!isDropdownOpen)}
        >
            <span className="truncate">
                {selectedItems.length > 0 ? `${selectedItems.length} Selected` : "Select Items (Max 5)"}
            </span>
            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 text-slate-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
            </svg>
        </div>

        {isDropdownOpen && (
            <div className="absolute top-full left-0 w-full mt-1 bg-slate-900 border border-slate-600 rounded-md shadow-xl max-h-96 overflow-hidden flex flex-col z-50">
                <input 
                    type="text" 
                    placeholder="Search items..." 
                    className="w-full bg-slate-800 text-slate-200 px-3 py-2 border-b border-slate-700 focus:outline-none focus:border-blue-500 text-sm"
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    autoFocus
                />
                <div className="overflow-y-auto flex-1 p-1">
                    {filteredItems.map(item => (
                        <div 
                            key={item}
                            className={`px-3 py-2 text-sm cursor-pointer rounded flex items-center gap-2 hover:bg-slate-800 ${selectedItems.includes(item) ? 'bg-slate-800 text-blue-400' : 'text-slate-300'}`}
                            onClick={() => toggleItem(item)}
                        >
                            <div className={`w-4 h-4 border rounded flex items-center justify-center ${selectedItems.includes(item) ? 'border-blue-500 bg-blue-500' : 'border-slate-500'}`}>
                                {selectedItems.includes(item) && (
                                    <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3 text-white" viewBox="0 0 20 20" fill="currentColor">
                                        <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" />
                                    </svg>
                                )}
                            </div>
                            <span className="truncate">{item}</span>
                        </div>
                    ))}
                    {filteredItems.length === 0 && (
                        <div className="px-3 py-4 text-center text-slate-500 text-sm">No items found</div>
                    )}
                </div>
                <div className="p-2 border-t border-slate-700 bg-slate-800 text-xs text-slate-400 text-center">
                    {selectedItems.length}/5 Selected
                </div>
            </div>
        )}
      </div>

      <div className="flex flex-wrap items-center gap-4">
        {/* Date Range */}
        <div className="flex items-center gap-2 bg-slate-900 rounded border border-slate-600 px-2 py-1">
            <span className="text-xs text-slate-400 uppercase font-semibold">Range</span>
            <input 
                type="date" 
                value={dateRange[0]}
                min={minDate}
                max={dateRange[1]}
                onChange={(e) => onDateRangeChange([e.target.value, dateRange[1]])}
                className="bg-transparent text-sm text-slate-200 focus:outline-none w-28 cursor-pointer"
            />
            <span className="text-slate-500">-</span>
            <input 
                type="date" 
                value={dateRange[1]}
                min={dateRange[0]}
                max={maxDate}
                onChange={(e) => onDateRangeChange([dateRange[0], e.target.value])}
                className="bg-transparent text-sm text-slate-200 focus:outline-none w-28 cursor-pointer"
            />
        </div>

        {/* Scale Toggle */}
        <div className="flex bg-slate-900 rounded border border-slate-600 p-1">
            {[ScaleType.LINEAR, ScaleType.LOG, ScaleType.PERCENTAGE].map((s) => (
                <button
                    key={s}
                    onClick={() => onScaleChange(s)}
                    className={`px-3 py-1 text-xs font-medium rounded transition-colors ${scale === s ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-slate-200'}`}
                >
                    {s === ScaleType.PERCENTAGE ? '%' : s}
                </button>
            ))}
        </div>

        {/* Currency Toggle */}
        <div className="flex bg-slate-900 rounded border border-slate-600 p-1">
             {[Currency.TRY, Currency.USD, Currency.EUR, Currency.BRENT].map((c) => (
                <button
                    key={c}
                    onClick={() => onCurrencyChange(c)}
                    className={`px-3 py-1 text-xs font-medium rounded transition-colors ${currency === c ? 'bg-emerald-600 text-white' : 'text-slate-400 hover:text-slate-200'}`}
                >
                    {c}
                </button>
            ))}
        </div>
      </div>
    </div>
  );
};

export default Controls;

import React, { useMemo } from 'react';
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
  ReferenceLine
} from 'recharts';
import { MarketDataPoint, Currency, ScaleType } from '../types';

interface PriceChartProps {
  data: MarketDataPoint[];
  selectedItems: string[];
  currency: Currency;
  scale: ScaleType;
  colors: string[];
}

const PriceChart: React.FC<PriceChartProps> = ({ data, selectedItems, currency, scale, colors }) => {

  const chartData = useMemo(() => {
    if (data.length === 0) return [];

    const baseValues: Record<string, number> = {};

    // Find base values for percentage calculation (first valid data point in range)
    if (scale === ScaleType.PERCENTAGE) {
        selectedItems.forEach(item => {
            const val = data[0][item] as number;
            const rates = data[0]._rates as any;
            if(val !== undefined && val !== null) {
                let converted = val;
                if (currency !== Currency.TRY && rates) {
                   if (currency === Currency.BRENT) converted = val / (rates['BRENT_TL'] || 1);
                   else converted = val / (rates[currency] || 1);
                }
                baseValues[item] = converted;
            }
        });
    }

    return data.map(row => {
      const newRow: any = { date: row.date, timestamp: row.timestamp };
      const rates = row._rates as any;

      selectedItems.forEach(item => {
        let val = row[item] as number;

        if (val === null || val === undefined) {
             newRow[item] = null;
             return;
        }

        // Currency Conversion
        if (currency !== Currency.TRY) {
            if (rates) {
                if (currency === Currency.BRENT) {
                    // Price in TL divided by Brent Price in TL gives "Barrels of Oil" equivalent
                    // Or more likely user wants Price in USD / Oil Price? 
                    // Prompt says "Brent petrol TL fiyatı cinsinden". 
                    // So Item Price (TL) / Brent (TL) = quantity of barrels.
                    const brentTL = rates['BRENT_TL'];
                    if (brentTL) val = val / brentTL;
                    else val = null as any; 
                } else {
                    const rate = rates[currency];
                    if (rate) val = val / rate;
                    else val = null as any;
                }
            } else {
                val = null as any;
            }
        }

        // Scale Calculation
        if (val !== null) {
            if (scale === ScaleType.PERCENTAGE) {
                const base = baseValues[item];
                if (base) {
                    newRow[item] = ((val - base) / base) * 100;
                } else {
                    newRow[item] = 0;
                }
            } else {
                newRow[item] = val;
            }
        }
      });
      return newRow;
    });
  }, [data, selectedItems, currency, scale]);

  if (selectedItems.length === 0) {
    return (
        <div className="h-[500px] w-full flex items-center justify-center text-slate-500 bg-slate-900 border border-slate-800 rounded-lg">
            <p>Select items to visualize data</p>
        </div>
    );
  }

  const formatYAxis = (val: number) => {
      if (scale === ScaleType.PERCENTAGE) return `${val.toFixed(0)}%`;
      if (Math.abs(val) < 1) return val.toFixed(3);
      if (Math.abs(val) < 10) return val.toFixed(2);
      return val.toFixed(0);
  };

  const CustomTooltip = ({ active, payload, label }: any) => {
    if (active && payload && payload.length) {
      return (
        <div className="bg-slate-800 border border-slate-600 p-3 rounded shadow-xl text-sm z-50">
          <p className="text-slate-400 mb-2">{label}</p>
          {payload.map((entry: any, index: number) => (
            <div key={index} className="flex items-center gap-2 mb-1">
              <span className="w-2 h-2 rounded-full" style={{ backgroundColor: entry.color }}></span>
              <span className="text-slate-200 font-medium">{entry.name}:</span>
              <span className="text-slate-100 ml-auto font-mono">
                {entry.value !== null ? 
                    (scale === ScaleType.PERCENTAGE 
                        ? `${entry.value.toFixed(2)}%` 
                        : entry.value.toLocaleString(undefined, { maximumFractionDigits: 2 }))
                    : 'N/A'}
                 {scale !== ScaleType.PERCENTAGE && <span className="ml-1 text-xs text-slate-500">{currency}</span>}
              </span>
            </div>
          ))}
        </div>
      );
    }
    return null;
  };

  return (
    <div className="h-[500px] w-full bg-slate-900 border border-slate-800 rounded-lg p-4">
      <ResponsiveContainer width="100%" height="100%">
        <LineChart data={chartData} margin={{ top: 10, right: 30, left: 0, bottom: 0 }}>
          <CartesianGrid strokeDasharray="3 3" stroke="#2a2e39" vertical={false} />
          <XAxis 
            dataKey="date" 
            stroke="#64748b" 
            tick={{ fill: '#64748b', fontSize: 12 }}
            tickFormatter={(str) => str.substring(0, 7)}
            minTickGap={30}
          />
          <YAxis 
            scale={scale === ScaleType.LOG ? 'log' : 'linear'}
            domain={scale === ScaleType.LOG ? ['auto', 'auto'] : ['auto', 'auto']}
            stroke="#64748b"
            tick={{ fill: '#64748b', fontSize: 12 }}
            tickFormatter={formatYAxis}
            width={60}
          />
          <Tooltip content={<CustomTooltip />} />
          <Legend wrapperStyle={{ paddingTop: '10px' }} />
          {scale === ScaleType.PERCENTAGE && (
            <ReferenceLine y={0} stroke="#475569" strokeDasharray="3 3" />
          )}
          {selectedItems.map((item, index) => (
            <Line
              key={item}
              type="monotone"
              dataKey={item}
              stroke={colors[index % colors.length]}
              strokeWidth={2}
              dot={false}
              activeDot={{ r: 4, strokeWidth: 0 }}
              connectNulls
              animationDuration={500}
            />
          ))}
        </LineChart>
      </ResponsiveContainer>
    </div>
  );
};

export default PriceChart;

import React, { useMemo } from 'react';
import { MarketDataPoint, Currency } from '../types';

interface DataTableProps {
  data: MarketDataPoint[];
  selectedItems: string[];
  currency: Currency;
}

const DataTable: React.FC<DataTableProps> = ({ data, selectedItems, currency }) => {
  // Sort reverse chronological
  const reversedData = useMemo(() => [...data].reverse(), [data]);

  if (selectedItems.length === 0) return null;

  return (
    <div className="mt-6 border border-slate-800 rounded-lg overflow-hidden bg-slate-900">
      <div className="max-h-[400px] overflow-auto">
        <table className="w-full text-sm text-left">
          <thead className="text-xs text-slate-400 uppercase bg-slate-950 sticky top-0 z-10">
            <tr>
              <th className="px-6 py-3 font-medium border-b border-slate-800">Date</th>
              {selectedItems.map(item => (
                <th key={item} className="px-6 py-3 font-medium border-b border-slate-800">
                  {item} <span className="text-slate-600 text-[10px]">({currency})</span>
                </th>
              ))}
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-800">
            {reversedData.map((row) => {
               const rates = row._rates as any;
               return (
                <tr key={row.date} className="hover:bg-slate-800/50 transition-colors">
                    <td className="px-6 py-3 text-slate-300 font-mono whitespace-nowrap">{row.date}</td>
                    {selectedItems.map(item => {
                        let val = row[item] as number;
                        if(val === null || val === undefined) return <td key={`${row.date}-${item}`} className="px-6 py-3 text-slate-600">-</td>;

                        if (currency !== Currency.TRY && rates) {
                            if (currency === Currency.BRENT) {
                                const brentTL = rates['BRENT_TL'];
                                if (brentTL) val = val / brentTL;
                                else val = 0; 
                            } else {
                                const rate = rates[currency];
                                if (rate) val = val / rate;
                                else val = 0;
                            }
                        }

                        return (
                            <td key={`${row.date}-${item}`} className="px-6 py-3 text-slate-200">
                                {val.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
                            </td>
                        );
                    })}
                </tr>
               );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default DataTable;

import React, { useState, useMemo } from 'react';
import Header from './components/Header';
import Controls from './components/Controls';
import PriceChart from './components/PriceChart';
import DataTable from './components/DataTable';
import { marketData } from './services/dataService';
import { Currency, ScaleType } from './types';

// TradingView inspired colors
const CHART_COLORS = [
  '#2962FF', // Blue
  '#E91E63', // Pink
  '#F6D046', // Yellow
  '#26A69A', // Teal
  '#FF5252', // Red
];

const App: React.FC = () => {
  const [selectedItems, setSelectedItems] = useState<string[]>(['Ekmek', 'Benzin']);
  const [currency, setCurrency] = useState<Currency>(Currency.TRY);
  const [scale, setScale] = useState<ScaleType>(ScaleType.LINEAR);

  // Initialize date range based on available data
  const minDataDate = marketData[0]?.date || '2015-01-01';
  const maxDataDate = marketData[marketData.length - 1]?.date || new Date().toISOString().split('T')[0];
  const [dateRange, setDateRange] = useState<[string, string]>([minDataDate, maxDataDate]);

  // Filter data based on date range
  const filteredData = useMemo(() => {
    const start = new Date(dateRange[0]).getTime();
    const end = new Date(dateRange[1]).getTime();
    return marketData.filter(d => d.timestamp >= start && d.timestamp <= end);
  }, [dateRange]);

  return (
    <div className="min-h-screen bg-slate-950 text-slate-200 font-sans selection:bg-blue-500 selection:text-white">
      <Header />

      <main className="flex flex-col h-full">
        <Controls 
          selectedItems={selectedItems}
          onItemsChange={setSelectedItems}
          currency={currency}
          onCurrencyChange={setCurrency}
          scale={scale}
          onScaleChange={setScale}
          dateRange={dateRange}
          onDateRangeChange={setDateRange}
          minDate={minDataDate}
          maxDate={maxDataDate}
        />

        <div className="p-4 lg:p-6 space-y-6">

          {/* Chart Section */}
          <div className="w-full">
             <div className="flex items-center justify-between mb-4">
               <h2 className="text-lg font-semibold text-slate-100 flex items-center gap-2">
                 Market Performance
                 <span className="px-2 py-0.5 rounded bg-slate-800 text-xs text-slate-400 border border-slate-700">
                    {currency}
                 </span>
               </h2>
               {selectedItems.length > 0 && (
                   <div className="flex gap-2">
                     {selectedItems.map((item, i) => (
                        <div key={item} className="flex items-center gap-1.5 px-2 py-1 bg-slate-800/50 rounded border border-slate-700">
                            <div className="w-2 h-2 rounded-full" style={{backgroundColor: CHART_COLORS[i % CHART_COLORS.length]}}></div>
                            <span className="text-xs text-slate-300">{item}</span>
                        </div>
                     ))}
                   </div>
               )}
             </div>

             <PriceChart 
                data={filteredData} 
                selectedItems={selectedItems}
                currency={currency}
                scale={scale}
                colors={CHART_COLORS}
             />
          </div>

          {/* Data Table Section */}
          <div>
            <h2 className="text-lg font-semibold text-slate-100 mb-4">Historical Data</h2>
            <DataTable 
                data={filteredData}
                selectedItems={selectedItems}
                currency={currency}
            />
          </div>

        </div>
      </main>
    </div>
  );
};

export default App;

