import React, { useState, useRef, useEffect } from 'react';
import { Currency, ScaleType } from '../types';
import { availableItems } from '../services/dataService';

interface ControlsProps {
  selectedItems: string[];
  onItemsChange: (items: string[]) => void;
  currency: Currency;
  onCurrencyChange: (c: Currency) => void;
  scale: ScaleType;
  onScaleChange: (s: ScaleType) => void;
  dateRange: [string, string];
  onDateRangeChange: (range: [string, string]) => void;
  minDate: string;
  maxDate: string;
}

const Controls: React.FC<ControlsProps> = ({
  selectedItems,
  onItemsChange,
  currency,
  onCurrencyChange,
  scale,
  onScaleChange,
  dateRange,
  onDateRangeChange,
  minDate,
  maxDate
}) => {
  const [isDropdownOpen, setIsDropdownOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const dropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsDropdownOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  const toggleItem = (item: string) => {
    if (selectedItems.includes(item)) {
      onItemsChange(selectedItems.filter(i => i !== item));
    } else {
      onItemsChange([...selectedItems, item]);
    }
  };

  const filteredItems = availableItems.filter(item => 
    item.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const formatMonth = (dateStr: string) => {
      if (!dateStr) return '';
      return dateStr.substring(0, 7);
  };

  return (
    <div className="bg-slate-900 border-b border-slate-800 p-4 sticky top-0 z-20 shadow-lg">
      <div className="flex flex-col lg:flex-row gap-4 justify-between items-start lg:items-center">

        {/* Item Selector */}
        <div className="relative w-full lg:w-1/3" ref={dropdownRef}>
          <label className="block text-xs text-slate-400 mb-1">Ürün Seçimi</label>
          <button
            onClick={() => setIsDropdownOpen(!isDropdownOpen)}
            className="w-full bg-slate-800 border border-slate-700 text-slate-200 rounded-md px-3 py-2 text-left text-sm focus:outline-none focus:ring-2 focus:ring-blue-500 flex justify-between items-center"
          >
            <span className="truncate">
              {selectedItems.length > 0 ? `${selectedItems.length} ürün seçildi` : 'Ürün seçiniz...'}
            </span>
            <svg className="w-4 h-4 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" /></svg>
          </button>

          {isDropdownOpen && (
            <div className="absolute top-full left-0 w-full mt-1 bg-slate-800 border border-slate-700 rounded-md shadow-xl z-50 max-h-[400px] flex flex-col">
              <div className="p-2 border-b border-slate-700">
                <input
                  type="text"
                  placeholder="Ürün ara..."
                  className="w-full bg-slate-900 border border-slate-700 rounded px-2 py-1.5 text-sm text-slate-200 focus:outline-none focus:border-blue-500"
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  autoFocus
                />
              </div>
              <div className="overflow-y-auto flex-1 p-2 space-y-1">
                {filteredItems.map(item => (
                  <label key={item} className="flex items-center gap-2 p-1.5 hover:bg-slate-700 rounded cursor-pointer group">
                    <input
                      type="checkbox"
                      checked={selectedItems.includes(item)}
                      onChange={() => toggleItem(item)}
                      className="rounded border-slate-600 bg-slate-900 text-blue-600 focus:ring-offset-slate-800 focus:ring-blue-500"
                    />
                    <span className="text-sm text-slate-300 group-hover:text-white transition-colors">{item}</span>
                  </label>
                ))}
                {filteredItems.length === 0 && (
                  <div className="text-center text-slate-500 py-4 text-sm">Ürün bulunamadı</div>
                )}
              </div>
            </div>
          )}
        </div>

        <div className="flex flex-wrap gap-4 items-center w-full lg:w-auto">
             {/* Currency */}
             <div>
                <label className="block text-xs text-slate-400 mb-1">Para Birimi</label>
                <div className="flex bg-slate-800 rounded-md border border-slate-700 p-0.5">
                    {Object.values(Currency).map(c => (
                        <button
                            key={c}
                            onClick={() => onCurrencyChange(c)}
                            className={`px-3 py-1.5 text-xs font-medium rounded ${currency === c ? 'bg-blue-600 text-white shadow-sm' : 'text-slate-400 hover:text-slate-200'}`}
                        >
                            {c}
                        </button>
                    ))}
                </div>
             </div>

             {/* Scale - Converted to Buttons */}
             <div>
                <label className="block text-xs text-slate-400 mb-1">Ölçek</label>
                <div className="flex bg-slate-800 rounded-md border border-slate-700 p-0.5">
                    {Object.values(ScaleType).map(s => (
                        <button
                            key={s}
                            onClick={() => onScaleChange(s)}
                            className={`px-3 py-1.5 text-xs font-medium rounded ${scale === s ? 'bg-blue-600 text-white shadow-sm' : 'text-slate-400 hover:text-slate-200'}`}
                        >
                            {s}
                        </button>
                    ))}
                </div>
             </div>

             {/* Date Range - Using Month Picker */}
             <div className="flex gap-2">
                <div>
                    <label className="block text-xs text-slate-400 mb-1">Başlangıç</label>
                    <input 
                        type="month" 
                        value={formatMonth(dateRange[0])} 
                        min={formatMonth(minDate)}
                        max={formatMonth(dateRange[1])}
                        onChange={(e) => onDateRangeChange([`${e.target.value}-01`, dateRange[1]])}
                        className="bg-slate-800 border border-slate-700 text-slate-200 text-sm rounded-md px-2 py-1.5 focus:outline-none focus:ring-2 focus:ring-blue-500"
                    />
                </div>
                <div>
                    <label className="block text-xs text-slate-400 mb-1">Bitiş</label>
                    <input 
                        type="month" 
                        value={formatMonth(dateRange[1])} 
                        min={formatMonth(dateRange[0])}
                        max={formatMonth(maxDate)}
                        onChange={(e) => onDateRangeChange([dateRange[0], `${e.target.value}-01`])}
                        className="bg-slate-800 border border-slate-700 text-slate-200 text-sm rounded-md px-2 py-1.5 focus:outline-none focus:ring-2 focus:ring-blue-500"
                    />
                </div>
             </div>
        </div>
      </div>

      {/* Selected Items Tags */}
      <div className="mt-3 flex flex-wrap gap-2">
        {selectedItems.map(item => (
            <span key={item} className="inline-flex items-center gap-1 px-2 py-1 rounded-md bg-slate-800 border border-slate-700 text-xs text-slate-300">
                {item}
                <button onClick={() => toggleItem(item)} className="hover:text-red-400 focus:outline-none">
                    <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
                </button>
            </span>
        ))}
        {selectedItems.length === 0 && (
            <span className="text-xs text-slate-500 italic">Ürün seçilmedi. Listeden ürün ekleyiniz.</span>
        )}
      </div>

    </div>
  );
};

export default Controls;

import React, { useMemo } from 'react';
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
  ReferenceLine
} from 'recharts';
import { MarketDataPoint, Currency, ScaleType } from '../types';

interface PriceChartProps {
  data: MarketDataPoint[];
  selectedItems: string[];
  currency: Currency;
  scale: ScaleType;
  colors: string[];
}

const PriceChart: React.FC<PriceChartProps> = ({ data, selectedItems, currency, scale, colors }) => {

  const chartData = useMemo(() => {
    if (data.length === 0) return [];

    const baseValues: Record<string, number> = {};

    // Find base values for percentage calculation (first valid data point in range)
    if (scale === ScaleType.PERCENTAGE) {
        selectedItems.forEach(item => {
            // Find first non-null value for this item
            const firstValidRow = data.find(r => r[item] !== null && r[item] !== undefined);
            if (firstValidRow) {
                const val = firstValidRow[item] as number;
                const rates = firstValidRow._rates as any;
                let converted = val;
                if (currency !== Currency.TRY && rates) {
                   if (currency === Currency.BRENT) converted = val / (rates['BRENT_TL'] || 1);
                   else converted = val / (rates[currency] || 1);
                }
                baseValues[item] = converted;
            }
        });
    }

    return data.map(row => {
      const newRow: any = { date: row.date, timestamp: row.timestamp };
      const rates = row._rates as any;

      selectedItems.forEach(item => {
        let val = row[item] as number;

        if (val === null || val === undefined) {
             newRow[item] = null;
             return;
        }

        // Currency Conversion
        if (currency !== Currency.TRY) {
            if (rates) {
                if (currency === Currency.BRENT) {
                    const brentTL = rates['BRENT_TL'];
                    if (brentTL) val = val / brentTL;
                    else val = null as any; 
                } else {
                    const rate = rates[currency];
                    if (rate) val = val / rate;
                    else val = null as any;
                }
            } else {
                val = null as any;
            }
        }

        // Scale Calculation
        if (val !== null) {
            if (scale === ScaleType.PERCENTAGE) {
                const base = baseValues[item];
                if (base) {
                    newRow[item] = ((val - base) / base) * 100;
                } else {
                    newRow[item] = 0;
                }
            } else {
                newRow[item] = val;
            }
        }
      });
      return newRow;
    });
  }, [data, selectedItems, currency, scale]);

  if (selectedItems.length === 0) {
    return (
        <div className="h-[500px] w-full flex items-center justify-center text-slate-500 bg-slate-900 border border-slate-800 rounded-lg">
            <p>Veri görüntülemek için ürün seçiniz</p>
        </div>
    );
  }

  const formatYAxis = (val: number) => {
      if (scale === ScaleType.PERCENTAGE) return `${val.toFixed(0)}%`;
      if (Math.abs(val) < 0.001) return val.toFixed(5);
      if (Math.abs(val) < 1) return val.toFixed(3);
      if (Math.abs(val) < 10) return val.toFixed(2);
      return val.toFixed(0);
  };

  const formatXAxis = (dateStr: string) => {
      try {
        const date = new Date(dateStr);
        return date.toLocaleDateString('tr-TR', { month: 'short', year: 'numeric' });
      } catch (e) {
          return dateStr;
      }
  }

  const CustomTooltip = ({ active, payload, label }: any) => {
    if (active && payload && payload.length) {
      let dateLabel = label;
      try {
          const date = new Date(label);
          dateLabel = date.toLocaleDateString('tr-TR', { day: 'numeric', month: 'long', year: 'numeric' });
      } catch (e) {}

      return (
        <div className="bg-slate-800/95 border border-slate-700 p-3 rounded-md shadow-2xl backdrop-blur-sm text-sm z-50">
          <p className="text-slate-400 mb-2 font-mono text-xs">{dateLabel}</p>
          <div className="space-y-1">
            {payload.map((entry: any, index: number) => (
                <div key={index} className="flex items-center gap-3">
                <div className="flex items-center gap-2 min-w-[120px]">
                    <span className="w-2 h-2 rounded-full shadow-sm" style={{ backgroundColor: entry.color }}></span>
                    <span className="text-slate-300 font-medium truncate max-w-[150px]">{entry.name}</span>
                </div>
                <span className="text-slate-100 font-mono ml-auto">
                    {entry.value !== null ? 
                        (scale === ScaleType.PERCENTAGE 
                            ? `${entry.value > 0 ? '+' : ''}${entry.value.toFixed(2)}%` 
                            : entry.value.toLocaleString('tr-TR', { maximumFractionDigits: 4 }))
                        : 'N/A'}
                </span>
                </div>
            ))}
          </div>
        </div>
      );
    }
    return null;
  };

  // Safe domain for log scale
  const isLogSafe = scale === ScaleType.LOG && !chartData.some(row => selectedItems.some(item => {
      const val = row[item];
      return typeof val === 'number' && val <= 0;
  }));

  // Fallback to linear if log is unsafe (negative/zero values)
  const effectiveScale = isLogSafe ? 'log' : 'linear';

  return (
    <div className="h-[500px] w-full bg-slate-900 border border-slate-800 rounded-lg p-1 sm:p-4">
      <ResponsiveContainer width="100%" height="100%">
        <LineChart data={chartData} margin={{ top: 10, right: 10, left: 0, bottom: 0 }}>
          <CartesianGrid strokeDasharray="3 3" stroke="#1e293b" vertical={true} horizontal={true} />
          <XAxis 
            dataKey="date" 
            stroke="#64748b" 
            tick={{ fill: '#64748b', fontSize: 11, fontFamily: 'monospace' }}
            tickFormatter={formatXAxis}
            minTickGap={40}
            tickLine={false}
            axisLine={{ stroke: '#334155' }}
          />
          <YAxis 
            scale={effectiveScale}
            domain={['auto', 'auto']}
            stroke="#64748b"
            tick={{ fill: '#64748b', fontSize: 11, fontFamily: 'monospace' }}
            tickFormatter={formatYAxis}
            width={55}
            tickLine={false}
            axisLine={{ stroke: '#334155' }}
          />
          <Tooltip content={<CustomTooltip />} cursor={{ stroke: '#475569', strokeDasharray: '4 4' }} />
          <Legend wrapperStyle={{ paddingTop: '15px', fontSize: '12px' }} />
          {scale === ScaleType.PERCENTAGE && (
            <ReferenceLine y={0} stroke="#475569" strokeDasharray="3 3" />
          )}
          {selectedItems.map((item, index) => (
            <Line
              key={item}
              type="monotone"
              dataKey={item}
              stroke={colors[index % colors.length]}
              strokeWidth={2}
              dot={false}
              activeDot={{ r: 5, strokeWidth: 2, stroke: '#1e293b' }}
              connectNulls
              animationDuration={500}
            />
          ))}
        </LineChart>
      </ResponsiveContainer>
    </div>
  );
};

export default PriceChart;

import React, { useMemo } from 'react';
import { MarketDataPoint, Currency } from '../types';

interface DataTableProps {
  data: MarketDataPoint[];
  selectedItems: string[];
  currency: Currency;
}

const DataTable: React.FC<DataTableProps> = ({ data, selectedItems, currency }) => {
  // Sort reverse chronological
  const reversedData = useMemo(() => [...data].reverse(), [data]);

  if (selectedItems.length === 0) return null;

  return (
    <div className="mt-6 border border-slate-800 rounded-lg overflow-hidden bg-slate-900">
      <div className="max-h-[400px] overflow-auto">
        <table className="w-full text-sm text-left">
          <thead className="text-xs text-slate-400 uppercase bg-slate-950 sticky top-0 z-10">
            <tr>
              <th className="px-6 py-3 font-medium border-b border-slate-800">Tarih</th>
              {selectedItems.map(item => (
                <th key={item} className="px-6 py-3 font-medium border-b border-slate-800">
                  {item} <span className="text-slate-600 text-[10px]">({currency})</span>
                </th>
              ))}
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-800">
            {reversedData.map((row) => {
               const rates = row._rates as any;
               const dateObj = new Date(row.date);
               const formattedDate = dateObj.toLocaleDateString('tr-TR', { year: 'numeric', month: 'long' });

               return (
                <tr key={row.date} className="hover:bg-slate-800/50 transition-colors">
                    <td className="px-6 py-3 text-slate-300 font-mono whitespace-nowrap">{formattedDate}</td>
                    {selectedItems.map(item => {
                        let val = row[item] as number;
                        if(val === null || val === undefined) return <td key={`${row.date}-${item}`} className="px-6 py-3 text-slate-600">-</td>;

                        if (currency !== Currency.TRY && rates) {
                            if (currency === Currency.BRENT) {
                                const brentTL = rates['BRENT_TL'];
                                if (brentTL) val = val / brentTL;
                                else val = 0; 
                            } else {
                                const rate = rates[currency];
                                if (rate) val = val / rate;
                                else val = 0;
                            }
                        }

                        return (
                            <td key={`${row.date}-${item}`} className="px-6 py-3 text-slate-200">
                                {val.toLocaleString('tr-TR', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
                            </td>
                        );
                    })}
                </tr>
               );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default DataTable;

import React, { useState, useMemo, useEffect } from 'react';
import Header from './components/Header';
import Controls from './components/Controls';
import PriceChart from './components/PriceChart';
import DataTable from './components/DataTable';
import { marketData } from './services/dataService';
import { Currency, ScaleType } from './types';

// TradingView inspired colors
const CHART_COLORS = [
  '#2962FF', // Blue
  '#E91E63', // Pink
  '#F6D046', // Yellow
  '#26A69A', // Teal
  '#FF5252', // Red
];

const App: React.FC = () => {
  const [selectedItems, setSelectedItems] = useState<string[]>(['Ekmek', 'Benzin']);
  const [currency, setCurrency] = useState<Currency>(Currency.TRY);
  const [scale, setScale] = useState<ScaleType>(ScaleType.LINEAR);

  // Initialize date range based on available data
  // Safe access to marketData in case it's empty
  const minDataDate = marketData.length > 0 ? marketData[0].date : '2021-01-01';
  const maxDataDate = marketData.length > 0 ? marketData[marketData.length - 1].date : new Date().toISOString().split('T')[0];

  const [dateRange, setDateRange] = useState<[string, string]>([minDataDate, maxDataDate]);

  // Force update if data loads asynchronously (not applicable here but good practice)
  useEffect(() => {
     if(marketData.length > 0) {
         setDateRange([marketData[0].date, marketData[marketData.length - 1].date]);
     }
  }, []);

  // Filter data based on date range
  const filteredData = useMemo(() => {
    const start = new Date(dateRange[0]).getTime();
    const end = new Date(dateRange[1]).getTime();
    return marketData.filter(d => d.timestamp >= start && d.timestamp <= end);
  }, [dateRange]);

  return (
    <div className="min-h-screen bg-slate-950 text-slate-200 font-sans selection:bg-blue-500 selection:text-white">
      <Header />

      <main className="flex flex-col h-full">
        <Controls 
          selectedItems={selectedItems}
          onItemsChange={setSelectedItems}
          currency={currency}
          onCurrencyChange={setCurrency}
          scale={scale}
          onScaleChange={setScale}
          dateRange={dateRange}
          onDateRangeChange={setDateRange}
          minDate={minDataDate}
          maxDate={maxDataDate}
        />

        <div className="p-4 lg:p-6 space-y-6">

          {/* Chart Section */}
          <div className="w-full">
             <div className="flex items-center justify-between mb-4">
               <h2 className="text-lg font-semibold text-slate-100 flex items-center gap-2">
                 Piyasa Performansı
                 <span className="px-2 py-0.5 rounded bg-slate-800 text-xs text-slate-400 border border-slate-700">
                    {currency}
                 </span>
               </h2>
               {selectedItems.length > 0 && (
                   <div className="flex gap-2">
                     {selectedItems.map((item, i) => (
                        <div key={item} className="flex items-center gap-1.5 px-2 py-1 bg-slate-800/50 rounded border border-slate-700">
                            <div className="w-2 h-2 rounded-full" style={{backgroundColor: CHART_COLORS[i % CHART_COLORS.length]}}></div>
                            <span className="text-xs text-slate-300">{item}</span>
                        </div>
                     ))}
                   </div>
               )}
             </div>

             <PriceChart 
                data={filteredData} 
                selectedItems={selectedItems}
                currency={currency}
                scale={scale}
                colors={CHART_COLORS}
             />
          </div>

          {/* Data Table Section */}
          <div>
            <h2 className="text-lg font-semibold text-slate-100 mb-4">Tarihsel Veriler</h2>
            <DataTable 
                data={filteredData}
                selectedItems={selectedItems}
                currency={currency}
            />
          </div>

        </div>
      </main>
    </div>
  );
};

export default App;

