        '2021-01': 7.37, '2021-12': 13.53, '2022-01': 13.43, '2022-12': 18.63,
        '2023-06': 23.60, '2024-01': 30.20, '2024-06': 32.50, '2025-01': 36.50
    };

    const dates = Object.keys(keyPoints).sort();

    while (currentDate <= endDate) {
        const year = currentDate.getFullYear();
        const month = String(currentDate.getMonth() + 1).padStart(2, '0');
        const key = `${year}-${month}`;

        let usdRate = 0;

        // Find interpolation bounds
        let lowerDate = dates[0];
        let upperDate = dates[dates.length - 1];

        for(let i=0; i<dates.length; i++) {
            if (dates[i] <= key) lowerDate = dates[i];
            if (dates[i] >= key) { upperDate = dates[i]; break; }
        }

        if (lowerDate === upperDate) {
            usdRate = keyPoints[lowerDate];
        } else {
             const t1 = new Date(lowerDate + "-01").getTime();
             const t2 = new Date(upperDate + "-01").getTime();
             const tCur = new Date(key + "-01").getTime();
             const v1 = keyPoints[lowerDate];
             const v2 = keyPoints[upperDate];
             // Linear interpolation
             if (t2 !== t1) {
                usdRate = v1 + (v2 - v1) * ((tCur - t1) / (t2 - t1));
             } else {
                usdRate = v1;
             }
        }

        rates[key] = {
            USD: usdRate,
            EUR: usdRate * 1.1, 
            GBP: usdRate * 1.25,
            BRENT_TL: usdRate * 75, // Synthetic Brent multiplier
            BRENT_USD: 75
        };
        currentDate.setMonth(currentDate.getMonth() + 1);
    }
    return rates;
};

const parseCSV = (csv: string): any[] => {
  if (!csv) return [];
  const lines = csv.replace(/\r/g, '').trim().split('\n');
  if (lines.length < 2) return [];

  // Helper to split CSV line respecting quotes
  const splitLine = (line: string) => {
      const result = [];
      let current = '';
      let inQuote = false;
      for (let i = 0; i < line.length; i++) {
          const char = line[i];
          if (char === '"') {
              inQuote = !inQuote;
          } else if (char === ',' && !inQuote) {
              result.push(current);
              current = '';
          } else {
              current += char;
          }
      }
      result.push(current);
      return result;
  };

  // Parse Headers
  const headerLine = lines[0];
  const headers = splitLine(headerLine).map(h => h.trim().replace(/^"|"$/g, ''));

  const data = [];
  for (let i = 1; i < lines.length; i++) {
      const line = lines[i];
      if (!line.trim()) continue;

      const values = splitLine(line).map(v => v.trim().replace(/^"|"$/g, ''));
      const row: any = {};
      let hasDate = false;

      headers.forEach((header, index) => {
          const val = values[index];
          if (header === 'Tarih' || header === 'Date') {
              // Parse DD/MM/YYYY
              if (val && val.includes('/')) {
                  const parts = val.split('/');
                  if (parts.length === 3) {
                      // format YYYY-MM-DD for sorting/charting
                      row['date'] = `${parts[2]}-${parts[1]}-${parts[0]}`;
                      row['timestamp'] = new Date(row['date']).getTime();
                      hasDate = true;
                  }
              } else if (val && val.includes('-')) {
                   // Assume already YYYY-MM-DD or similar
                   row['date'] = val;
                   row['timestamp'] = new Date(val).getTime();
                   hasDate = true;
              }
          } else {
              const num = parseFloat(val);
              row[header] = isNaN(num) ? null : num;
          }
      });

      if (hasDate) {
          data.push(row);
      }
  }
  return data;
};

export const loadMarketData = async (): Promise<{ data: MarketDataPoint[], items: string[] }> => {
    let csvData = '';

    // 1. Try importing via Vite's raw loader
    if (rawCsvData && typeof rawCsvData === 'string' && rawCsvData.length > 0) {
        // Basic check if it looks like CSV
        if (rawCsvData.includes(',') || rawCsvData.includes('\n')) {
             csvData = rawCsvData;
        }
    }

    // 2. If import failed (e.g. not using Vite, or import returns path), try fetching
    if (!csvData) {
        try {
            console.log('Fetching CSV from /GRETL_TUFE.csv');
            const response = await fetch('/GRETL_TUFE.csv');
            if (response.ok) {
                csvData = await response.text();
            } else {
                console.error('Failed to fetch CSV:', response.statusText);
            }
        } catch (error) {
            console.error('Error fetching CSV:', error);
        }
    }

    if (!csvData) {
        console.error("Could not load CSV data from import or fetch.");
        return { data: [], items: [] };
    }

    const rawCpiData = parseCSV(csvData);
    const fxMap = generateFXRates(2015, 2026);

    const marketData: MarketDataPoint[] = rawCpiData.map((row: any) => {
        const date = row.date;
        if(!date) return null;

        const monthKey = date.substring(0, 7); // YYYY-MM
        const rates = fxMap[monthKey] || fxMap['2025-01']; // Default to latest if not found

        return {
            ...row,
            _rates: rates
        };
    }).filter(Boolean) as MarketDataPoint[];

    // Sort by timestamp
    marketData.sort((a, b) => a.timestamp - b.timestamp);

    const items = Object.keys(rawCpiData[0] || {}).filter(k => 
        k !== 'date' && k !== 'timestamp' && k !== 'Tarih' && k !== 'Date'
    );

    return { data: marketData, items };
};

