```typescript
const parseCSV = (csv: string): any[] => {
  if (!csv) return [];
  const lines = csv.replace(/\r/g, '').trim().split('\n');
  if (lines.length < 2) return [];

  // Helper to split CSV line respecting quotes
  const splitLine = (line: string) => {
      const result = [];
      let current = '';
      let inQuote = false;
      for (let i = 0; i < line.length; i++) {
          const char = line[i];
          if (char === '"') {
              inQuote = !inQuote;
          } else if (char === ',' && !inQuote) {
              result.push(current);
              current = '';
          } else {
              current += char;
          }
      }
      result.push(current);
      return result;
  };

  // Parse Headers
  const headerLine = lines[0];
  const headers = splitLine(headerLine).map(h => h.trim().replace(/^"|"$/g, ''));

  const data = [];
  for (let i = 1; i < lines.length; i++) {
      const line = lines[i];
      const parts = splitLine(line);

      // Skip invalid lines, or handle them gracefully
      if (parts.length !== headers.length) {
        continue; // Or log an error, or handle differently
      }

      const rates = {};
      for (let j = 0; j < headers.length; j++) {
          const header = headers[j];
          let value = parts[j].trim().replace(/^"|"$/g, ''); // Trim quotes

          if (header === 'Date') {
              // Assuming Date format, adjust parsing if needed
              rates[header] = value; // new Date(value);  // or use a dedicated date parsing library
          } else if (!isNaN(Number(value))) {
              rates[header] = parseFloat(value);
          } else {
              rates[header] = value;
          }
      }
      data.push(rates);
  }
  return data;
}
